import{_ as t,o as n,c as r,a2 as e}from"./chunks/framework.CHeM0PsO.js";const p=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"spv/laporan-mingguan.md","filePath":"spv/laporan-mingguan.md"}'),i={name:"spv/laporan-mingguan.md"};function s(d,a,o,g,u,l){return n(),r("div",null,[...a[0]||(a[0]=[e('<h2 id="bab-4-laporan-mingguan-evaluasi-taktis" tabindex="-1">BAB 4: LAPORAN MINGGUAN (EVALUASI TAKTIS) <a class="header-anchor" href="#bab-4-laporan-mingguan-evaluasi-taktis" aria-label="Permalink to &quot;BAB 4: LAPORAN MINGGUAN (EVALUASI TAKTIS)&quot;">​</a></h2><p>Laporan Mingguan diisi <strong>sekali setiap minggu</strong> dan berfungsi sebagai evaluasi taktis. Untuk meringankan beban Anda, <strong>sebagian besar data kuantitatif ditarik secara otomatis</strong> dari laporan harian.</p><h3 id="_4-1-tab-1-identitas-rekap-omset-evaluasi-produk" tabindex="-1">4.1 Tab 1: Identitas, Rekap Omset &amp; Evaluasi Produk <a class="header-anchor" href="#_4-1-tab-1-identitas-rekap-omset-evaluasi-produk" aria-label="Permalink to &quot;4.1 Tab 1: Identitas, Rekap Omset &amp; Evaluasi Produk&quot;">​</a></h3><p><strong>Langkah Pertama:</strong> Pilih <strong>Rentang Waktu</strong> (Dari Tanggal sampai Tanggal).</p><blockquote><p><strong>Peraturan 7 Hari:</strong> Sistem mengunci pilihan rentang waktu agar <strong>tepat 7 hari</strong> (misal: Senin sampai Minggu). Jika Anda memilih kurang atau lebih dari 7 hari, akan muncul <strong>peringatan merah</strong> yang memblokir proses selanjutnya.</p></blockquote><p>Setelah rentang valid, sistem menarik data otomatis:</p><table tabindex="0"><thead><tr><th>Apa yang Muncul Otomatis</th><th>Penjelasan</th></tr></thead><tbody><tr><td><strong>Tabel Rekap Omset (7 Hari)</strong></td><td>Anda <strong>tidak perlu mengetik</strong> — tabel ini terisi otomatis dengan data Target &amp; Omset per hari</td></tr><tr><td><strong>Total Target &amp; Aktual</strong></td><td>Penjumlahan otomatis 7 hari</td></tr><tr><td><strong>Bar Indikator (Warna)</strong></td><td>Hijau (≥100%), Oranye (80-99%), Merah (&lt;80%)</td></tr><tr><td><strong>Evaluasi Produk (Minuman, Makanan, Snack)</strong></td><td>Top 5 dan Bottom 3 per kategori — ditarik otomatis dari laporan harian Anda</td></tr></tbody></table><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi Sendiri</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Rencana Tindakan (Action Plan)</strong></td><td>Satu-satunya kolom yang harus diketik. Tulis strategi Anda untuk minggu depan berdasarkan data yang sudah tersaji</td></tr></tbody></table><h3 id="_4-2-tab-2-komplain-evaluasi-performa-staf" tabindex="-1">4.2 Tab 2: Komplain &amp; Evaluasi Performa Staf <a class="header-anchor" href="#_4-2-tab-2-komplain-evaluasi-performa-staf" aria-label="Permalink to &quot;4.2 Tab 2: Komplain &amp; Evaluasi Performa Staf&quot;">​</a></h3><p><strong>A. Komplain &amp; Kendala Mingguan:</strong></p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Total Kasus Komplain</strong></td><td>Isi sendiri (bukan otomatis — agar Anda sadar menghitung)</td></tr><tr><td><strong>Total Remake</strong></td><td>Angka berwarna merah (setiap remake = kerugian bahan baku)</td></tr><tr><td><strong>Penyebab Utama Komplain</strong></td><td>Sengaja teks bebas — Anda harus menyimpulkan akar masalah</td></tr><tr><td><strong>Kendala Utama Berulang</strong></td><td>Masalah yang terus muncul selama 7 hari</td></tr></tbody></table><p><strong>B. Evaluasi Performa Staf:</strong></p><p>Sistem akan menampilkan daftar nama staf outlet Anda. Setiap nama berbentuk kotak lipatan (Accordion):</p><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Pilihan</th><th>Dampak</th></tr></thead><tbody><tr><td><strong>Status Penilaian</strong></td><td><strong>Berkembang</strong> (ada inisiatif, belajar cepat), <strong>Stagnan</strong> (sekadar selesai, zona nyaman), <strong>Menurun</strong> (sering telat, lambat)</td><td>Data ini menjadi pondasi GM untuk keputusan gaji, bonus, atau SP</td></tr><tr><td><strong>Keterangan (Kendala &amp; Planning)</strong></td><td>Wajib dirincikan: apa kemajuan/kendalanya, dan rencana pelatihan minggu depan</td><td>Contoh: &quot;Sudah lancar kasir. Planning: minggu depan ajarkan kalibrasi grinder&quot;</td></tr></tbody></table><h3 id="_4-3-tab-3-rencana-perbaikan-tim-pengiriman" tabindex="-1">4.3 Tab 3: Rencana Perbaikan Tim &amp; Pengiriman <a class="header-anchor" href="#_4-3-tab-3-rencana-perbaikan-tim-pengiriman" aria-label="Permalink to &quot;4.3 Tab 3: Rencana Perbaikan Tim &amp; Pengiriman&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Yang Harus Anda Isi</th><th>Catatan</th></tr></thead><tbody><tr><td><strong>Rencana Perbaikan Tim</strong></td><td>Tindakan nyata yang akan Anda lakukan minggu depan</td></tr><tr><td><strong>Kebutuhan SPV / Tim</strong></td><td>Alat atau dukungan yang dibutuhkan (Contoh: &quot;Butuh lakban&quot;, &quot;Butuh training menu baru&quot;)</td></tr></tbody></table><p>Gunakan tombol <strong>&quot;TAMBAH&quot;</strong> untuk menambah baris jika rencana/kebutuhan lebih dari satu.</p><p><strong>Tiga Tombol Bawah:</strong></p><table tabindex="0"><thead><tr><th>Tombol</th><th>Fungsi</th></tr></thead><tbody><tr><td><strong>SIMPAN DRAFT</strong></td><td>Menyimpan semua isian di memori browser. Bisa dilanjutkan besok</td></tr><tr><td><strong>EXPORT PDF</strong></td><td>Mengunduh PDF ke HP Anda sebagai arsip pribadi (tidak mengirim ke server)</td></tr><tr><td><strong>TINJAU &amp; KIRIM LAPORAN</strong></td><td>Validasi data → jika lengkap, tampilkan Preview → Kirim Final</td></tr></tbody></table><hr>',20)])])}const b=t(i,[["render",s]]);export{p as __pageData,b as default};
